41	/*
42	 * Increments the timestamp when it is duplicated
43	 */
44	static void influxdb_tsmod(struct flb_time *ts, struct flb_time *dupe,
45	                           struct flb_time *last) {
46	    if (flb_time_equal(ts, last) || flb_time_equal(ts, dupe)) {
47	        ++dupe->tm.tv_nsec;
48	        flb_time_copy(last, ts);
49	        flb_time_copy(ts, dupe);
50	    }
51	    else {
52	        flb_time_copy(last, ts);
53	        flb_time_copy(dupe, ts);
54	    }
55	}
