57	/*
58	 * Convert the internal Fluent Bit data representation to the required one
59	 * by InfluxDB.
60	 */
61	static int influxdb_format(struct flb_config *config,
62	                           struct flb_input_instance *ins,
63	                           void *plugin_context,
64	                           void *flush_ctx,
65	                           int event_type,
66	                           const char *tag, int tag_len,
67	                           const void *data, size_t bytes,
68	                           void **out_data, size_t *out_size)
69	{
70	    int i;
71	    int ret;
72	    int n_size;
73	    uint64_t seq = 0;
74	    char *str = NULL;
75	    size_t str_size;
76	    char tmp[128];
77	    msgpack_object map;
78	    struct flb_time tm;
79	    struct influxdb_bulk *bulk = NULL;
80	    struct influxdb_bulk *bulk_head = NULL;
81	    struct influxdb_bulk *bulk_body = NULL;
82	    struct flb_log_event_decoder log_decoder;
83	    struct flb_log_event log_event;
84	    struct flb_influxdb *ctx = plugin_context;
85	
86	    ret = flb_log_event_decoder_init(&log_decoder, (char *) data, bytes);
87	
88	    if (ret != FLB_EVENT_DECODER_SUCCESS) {
89	        flb_plg_error(ctx->ins,
90	                      "Log event decoder initialization error : %d", ret);
91	
92	        return -1;
93	    }
94	
95	    /* Create the bulk composer */
96	    bulk = influxdb_bulk_create();
97	    if (!bulk) {
98	        goto error;
99	    }
100	
101	    bulk_head = influxdb_bulk_create();
102	    if (!bulk_head) {
103	        goto error;
104	    }
105	
106	    bulk_body = influxdb_bulk_create();
107	    if (!bulk_body) {
108	        goto error;
109	    }
110	
111	    while ((ret = flb_log_event_decoder_next(
112	                    &log_decoder,
113	                    &log_event)) == FLB_EVENT_DECODER_SUCCESS) {
114	        flb_time_copy(&tm, &log_event.timestamp);
115	
116	        map    = *log_event.body;
117	        n_size = map.via.map.size + 1;
118	
119	        seq = ctx->seq;
120	        if (ctx->seq + 1 >= 100000) {
121	            seq = 1;
122	        }
123	        else {
124	            ctx->seq++;
125	        }
126	
127	        ret = influxdb_bulk_append_header(bulk_head,
128	                                          tag, tag_len,
129	                                          seq,
130	                                          ctx->seq_name, ctx->seq_len);
131	        if (ret == -1) {
132	            goto error;
133	        }
134	
135	        for (i = 0; i < n_size - 1; i++) {
136	            msgpack_object *k = &map.via.map.ptr[i].key;
137	            msgpack_object *v = &map.via.map.ptr[i].val;
138	
139	            if (k->type != MSGPACK_OBJECT_BIN && k->type != MSGPACK_OBJECT_STR) {
140	                continue;
141	            }
142	
143	            int quote = FLB_FALSE;
144	
145	            /* key */
146	            const char *key = NULL;
147	            int key_len;
148	
149	            /* val */
150	            const char *val = NULL;
151	            int val_len;
152	
153	            if (k->type == MSGPACK_OBJECT_STR) {
154	                key = k->via.str.ptr;
155	                key_len = k->via.str.size;
156	            }
157	            else {
158	                key = k->via.bin.ptr;
159	                key_len = k->via.bin.size;
160	            }
161	
162	            /* Store value */
163	            if (v->type == MSGPACK_OBJECT_NIL) {
164	                /* Missing values are Null by default in InfluxDB */
165	                continue;
166	            }
167	            else if (v->type == MSGPACK_OBJECT_BOOLEAN) {
168	                if (v->via.boolean) {
169	                    val = "TRUE";
170	                    val_len = 4;
171	                }
172	                else {
173	                    val = "FALSE";
174	                    val_len = 5;
175	                }
176	            }
177	            else if (v->type == MSGPACK_OBJECT_POSITIVE_INTEGER) {
178	                val = tmp;
179	                if (ctx->use_influxdb_integer) {
180	                    val_len = snprintf(tmp, sizeof(tmp) - 1, "%" PRIu64 "i", v->via.u64);
181	                }
182	                else {
183	                    val_len = snprintf(tmp, sizeof(tmp) - 1, "%" PRIu64, v->via.u64);
184	                }
185	            }
186	            else if (v->type == MSGPACK_OBJECT_NEGATIVE_INTEGER) {
187	                val = tmp;
188	                if (ctx->use_influxdb_integer) {
189	                    val_len = snprintf(tmp, sizeof(tmp) - 1, "%" PRId64 "i", v->via.i64);
190	                }
191	                else {
192	                    val_len = snprintf(tmp, sizeof(tmp) - 1, "%" PRId64, v->via.i64);
193	                }
194	            }
195	            else if (v->type == MSGPACK_OBJECT_FLOAT || v->type == MSGPACK_OBJECT_FLOAT32) {
196	                val = tmp;
197	                val_len = snprintf(tmp, sizeof(tmp) - 1, "%f", v->via.f64);
198	            }
199	            else if (v->type == MSGPACK_OBJECT_STR) {
200	                /* String value */
201	                quote   = FLB_TRUE;
202	                val     = v->via.str.ptr;
203	                val_len = v->via.str.size;
204	            }
205	            else if (v->type == MSGPACK_OBJECT_BIN) {
206	                /* Bin value */
207	                quote   = FLB_TRUE;
208	                val     = v->via.bin.ptr;
209	                val_len = v->via.bin.size;
210	            }
211	
212	            if (!val || !key) {
213	                continue;
214	            }
215	
216	            /* is this a string ? */
217	            if (quote == FLB_TRUE) {
218	                ret = flb_utils_write_str_buf(val, val_len,
219	                                              &str, &str_size,
220	                                              config->json_escape_unicode);
221	                if (ret == -1) {
222	                    flb_errno();
223	                    goto error;
224	                }
225	
226	                val = str;
227	                val_len = str_size;
228	            }
229	
230	            if (is_tagged_key(ctx, key, key_len, v->type)) {
231	                /* Append key/value data into the bulk_head */
232	                ret = influxdb_bulk_append_kv(bulk_head,
233	                                              key, key_len,
234	                                              val, val_len,
235	                                              false);
236	            }
237	            else {
238	                /* Append key/value data into the bulk_body */
239	                ret = influxdb_bulk_append_kv(bulk_body,
240	                                              key, key_len,
241	                                              val, val_len,
242	                                              quote);
243	            }
244	
245	            if (quote == FLB_TRUE) {
246	                flb_free(str);
247	                str_size = 0;
248	            }
249	
250	            if (ret == -1) {
251	                flb_plg_error(ctx->ins, "cannot append key/value");
252	                goto error;
253	            }
254	        }
255	
256	        /* Check have data fields */
257	        if (bulk_body->len > 0) {
258	            /* Modify timestamp in avoidance of duplication */
259	            influxdb_tsmod(&tm, &ctx->ts_dupe, &ctx->ts_last);
260	            /* Append the timestamp */
261	            ret = influxdb_bulk_append_timestamp(bulk_body, &tm);
262	            if (ret == -1) {
263	                flb_plg_error(ctx->ins, "cannot append timestamp");
264	                goto error;
265	            }
266	
267	            /* Append collected data to final bulk */
268	            if (influxdb_bulk_append_bulk(bulk, bulk_head, '\n') != 0 ||
269	                influxdb_bulk_append_bulk(bulk, bulk_body, ' ') != 0) {
270	                goto error;
271	            }
272	        }
273	        else {
274	            flb_plg_warn(ctx->ins, "skip send record, "
275	                         "since no record available "
276	                         "or all fields are tagged in record");
277	            /* Following records maybe ok, so continue processing */
278	        }
279	
280	        /* Reset bulk_head and bulk_body */
281	        bulk_head->len = 0;
282	        bulk_body->len = 0;
283	    }
284	
285	    flb_log_event_decoder_destroy(&log_decoder);
286	
287	    *out_data = bulk->ptr;
288	    *out_size = bulk->len;
289	
290	    /*
291	     * Note: we don't destroy the bulk as we need to keep the allocated
292	     * buffer with the data. Instead we just release the bulk context and
293	     * return the bulk->ptr buffer
294	     */
295	    flb_free(bulk);
296	    influxdb_bulk_destroy(bulk_head);
297	    influxdb_bulk_destroy(bulk_body);
298	
299	    return 0;
300	
301	error:
302	    if (bulk != NULL) {
303	        influxdb_bulk_destroy(bulk);
304	    }
305	    if (bulk_head != NULL) {
306	        influxdb_bulk_destroy(bulk_head);
307	    }
308	    if (bulk_body != NULL) {
309	        influxdb_bulk_destroy(bulk_body);
310	    }
311	
312	    flb_log_event_decoder_destroy(&log_decoder);
313	
314	    return -1;
315	}
