317	static int cb_influxdb_init(struct flb_output_instance *ins, struct flb_config *config,
318	                            void *data)
319	{
320	    int ret;
321	    int io_flags = 0;
322	    const char *tmp;
323	    struct flb_upstream *upstream;
324	    struct flb_influxdb *ctx;
325	
326	    /* Set default network configuration */
327	    flb_output_net_default(FLB_INFLUXDB_HOST, FLB_INFLUXDB_PORT, ins);
328	
329	    /* Allocate plugin context */
330	    ctx = flb_calloc(1, sizeof(struct flb_influxdb));
331	    if (!ctx) {
332	        flb_errno();
333	        return -1;
334	    }
335	    ctx->ins = ins;
336	
337	    /* Register context with plugin instance */
338	    flb_output_set_context(ins, ctx);
339	
340	    /*
341	     * This plugin instance uses the HTTP client interface, let's register
342	     * it debugging callbacks.
343	     */
344	    flb_output_set_http_debug_callbacks(ins);
345	
346	    /* Load config map */
347	    ret = flb_output_config_map_set(ins, (void *) ctx);
348	    if (ret == -1) {
349	        return -1;
350	    }
351	
352	    if (ins->use_tls == FLB_TRUE) {
353	        io_flags = FLB_IO_TLS;
354	    }
355	    else {
356	        io_flags = FLB_IO_TCP;
357	    }
358	
359	    /* sequence tag */
360	    tmp = flb_output_get_property("sequence_tag", ins);
361	    if (!tmp) {
362	        ctx->seq_name = flb_strdup("_seq");
363	    }
364	    else if (strcmp(tmp, "off") == 0) {
365	        ctx->seq_name = flb_strdup("");
366	    }
367	    else {
368	        ctx->seq_name = flb_strdup(tmp);
369	    }
370	    ctx->seq_len = strlen(ctx->seq_name);
371	
372	    if (ctx->custom_uri) {
373	        /* custom URI endpoint (e.g: Grafana */
374	        if (ctx->custom_uri[0] != '/') {
375	            flb_plg_error(ctx->ins,
376	                          "'custom_uri' value must start wih a forward slash '/'");
377	            return -1;
378	        }
379	        snprintf(ctx->uri, sizeof(ctx->uri) - 1, "%s", ctx->custom_uri);
380	    }
381	    else if (ctx->bucket) {
382	        /* bucket: api v2 */
383	        snprintf(ctx->uri, sizeof(ctx->uri) - 1,
384	                 "/api/v2/write?org=%s&bucket=%s&precision=ns",
385	                 ctx->organization, ctx->bucket);
386	    }
387	    else {
388	        snprintf(ctx->uri, sizeof(ctx->uri) - 1,
389	                 "/write?db=%s&precision=n",
390	                 ctx->database);
391	    }
392	
393	    if (ins->host.ipv6 == FLB_TRUE) {
394	        io_flags |= FLB_IO_IPV6;
395	    }
396	
397	
398	    /* Tag_Keys */
399	    tmp = flb_output_get_property("tag_keys", ins);
400	    if (tmp) {
401	        ctx->tag_keys = flb_utils_split(tmp, ' ', 256);
402	    }
403	    else {
404	        ctx->tag_keys = NULL;
405	    }
406	
407	    /* Prepare an upstream handler */
408	    upstream = flb_upstream_create(config,
409	                                   ins->host.name,
410	                                   ins->host.port,
411	                                   io_flags,
412	                                   ins->tls);
413	    if (!upstream) {
414	        flb_free(ctx);
415	        return -1;
416	    }
417	    ctx->u   = upstream;
418	    ctx->seq = 0;
419	    flb_output_upstream_set(ctx->u, ins);
420	
421	    flb_time_zero(&ctx->ts_dupe);
422	    flb_time_zero(&ctx->ts_last);
423	
424	    flb_plg_debug(ctx->ins, "host=%s port=%i", ins->host.name, ins->host.port);
425	
426	    return 0;
427	}
