429	static int format_metrics(struct flb_output_instance *ins,
430	                          const void *data, size_t bytes,
431	                          char **out_buf, size_t *out_size)
432	{
433	    int ret;
434	    size_t off = 0;
435	    cfl_sds_t text;
436	    struct cmt *cmt = NULL;
437	
438	    /* get cmetrics context */
439	    ret = cmt_decode_msgpack_create(&cmt, (char *) data, bytes, &off);
440	    if (ret != 0) {
441	        flb_plg_error(ins, "could not process metrics payload");
442	        return -1;
443	    }
444	
445	    /* convert to text representation */
446	    text = cmt_encode_influx_create(cmt);
447	    if (!text) {
448	        cmt_destroy(cmt);
449	        return -1;
450	    }
451	
452	    /* destroy cmt context */
453	    cmt_destroy(cmt);
454	
455	    *out_buf = text;
456	    *out_size = flb_sds_len(text);
457	
458	    return 0;
459	}
