461	static void cb_influxdb_flush(struct flb_event_chunk *event_chunk,
462	                              struct flb_output_flush *out_flush,
463	                              struct flb_input_instance *i_ins,
464	                              void *out_context,
465	                              struct flb_config *config)
466	{
467	    int ret;
468	    int out_ret = FLB_OK;
469	    int is_metric = FLB_FALSE;
470	    size_t b_sent;
471	    size_t bytes_out;
472	    void *out_buf;
473	    char *pack;
474	    char tmp[128];
475	    struct mk_list *head;
476	    struct flb_connection *u_conn;
477	    struct flb_http_client *c;
478	    struct flb_config_map_val *mv;
479	    struct flb_slist_entry *key = NULL;
480	    struct flb_slist_entry *val = NULL;
481	    struct flb_influxdb *ctx = out_context;
482	
483	    /* Convert format: metrics / logs */
484	    if (event_chunk->type == FLB_EVENT_TYPE_METRICS) {
485	        /* format metrics */
486	        ret = format_metrics(ctx->ins,
487	                             (char *) event_chunk->data,
488	                             event_chunk->size,
489	                             &pack, &bytes_out);
490	        if (ret == -1) {
491	            FLB_OUTPUT_RETURN(FLB_ERROR);
492	        }
493	        is_metric = FLB_TRUE;
494	    }
495	    else {
496	        /* format logs */
497	        ret = influxdb_format(config, i_ins,
498	                              ctx, NULL,
499	                              event_chunk->type,
500	                              event_chunk->tag, flb_sds_len(event_chunk->tag),
501	                              event_chunk->data, event_chunk->size,
502	                              &out_buf, &bytes_out);
503	        if (ret != 0) {
504	            FLB_OUTPUT_RETURN(FLB_ERROR);
505	        }
506	
507	        pack = (char *) out_buf;
508	    }
509	
510	    /* Get upstream connection */
511	    u_conn = flb_upstream_conn_get(ctx->u);
512	    if (!u_conn) {
513	        if (is_metric) {
514	            cmt_encode_influx_destroy(pack);
515	        }
516	        else {
517	            flb_free(pack);
518	        }
519	        FLB_OUTPUT_RETURN(FLB_RETRY);
520	    }
521	
522	    /* Compose HTTP Client request */
523	    c = flb_http_client(u_conn, FLB_HTTP_POST, ctx->uri,
524	                        pack, bytes_out, NULL, 0, NULL, 0);
525	    flb_http_add_header(c, "User-Agent", 10, "Fluent-Bit", 10);
526	
527	    if (ctx->http_token) {
528	        ret = snprintf(tmp, sizeof(tmp) - 1, "Token %s", ctx->http_token);
529	        flb_http_add_header(c, FLB_HTTP_HEADER_AUTH, sizeof FLB_HTTP_HEADER_AUTH - 1, tmp, ret);
530	    }
531	    else if (ctx->http_user && ctx->http_passwd) {
532	        flb_http_basic_auth(c, ctx->http_user, ctx->http_passwd);
533	    }
534	
535	    /* Append custom headers if any */
536	    flb_config_map_foreach(head, mv, ctx->headers) {
537	        key = mk_list_entry_first(mv->val.list, struct flb_slist_entry, _head);
538	        val = mk_list_entry_last(mv->val.list, struct flb_slist_entry, _head);
539	
540	        flb_http_add_header(c,
541	                            key->str, flb_sds_len(key->str),
542	                            val->str, flb_sds_len(val->str));
543	    }
544	
545	    /* Map debug callbacks */
546	    flb_http_client_debug(c, ctx->ins->callback);
547	
548	    ret = flb_http_do(c, &b_sent);
549	    if (ret == 0) {
550	        if (c->resp.status != 200 && c->resp.status != 204) {
551	            if (c->resp.payload_size > 0) {
552	                flb_plg_error(ctx->ins, "http_status=%i\n%s",
553	                              c->resp.status, c->resp.payload);
554	            }
555	            else {
556	                flb_plg_debug(ctx->ins, "http_status=%i",
557	                              c->resp.status);
558	            }
559	        }
560	        flb_plg_debug(ctx->ins, "http_do=%i OK", ret);
561	    }
562	    else {
563	        flb_plg_error(ctx->ins, "http_do=%i", ret);
564	        out_ret = FLB_RETRY;
565	    }
566	
567	    flb_http_client_destroy(c);
568	
569	    if (is_metric) {
570	        cmt_encode_influx_destroy(pack);
571	    }
572	    else {
573	        flb_free(pack);
574	    }
575	
576	    /* Release the connection */
577	    flb_upstream_conn_release(u_conn);
578	
579	    FLB_OUTPUT_RETURN(out_ret);
580	}
