582	static int cb_influxdb_exit(void *data, struct flb_config *config)
583	{
584	    struct flb_influxdb *ctx = data;
585	
586	    if (!ctx) {
587	        return 0;
588	    }
589	
590	    if (ctx->tag_keys) {
591	        flb_utils_split_free(ctx->tag_keys);
592	    }
593	
594	    if (ctx->seq_name) {
595	        flb_free(ctx->seq_name);
596	    }
597	
598	    flb_upstream_destroy(ctx->u);
599	    flb_free(ctx);
600	
601	    return 0;
602	}
