604	int is_tagged_key(struct flb_influxdb *ctx, const char *key, int kl, int type)
605	{
606	    if (type == MSGPACK_OBJECT_STR) {
607	        if (ctx->auto_tags) {
608	            return FLB_TRUE;
609	        }
610	    }
611	
612	    struct mk_list *head;
613	    struct flb_split_entry *entry;
614	
615	    if (ctx->tag_keys) {
616	        mk_list_foreach(head, ctx->tag_keys) {
617	            entry = mk_list_entry(head, struct flb_split_entry, _head);
618	            if (kl == entry->len && strncmp(key, entry->value, kl) == 0) {
619	                return FLB_TRUE;
620	            }
621	        }
622	    }
623	
624	    return FLB_FALSE;
625	}
