627	/* Configuration properties map */
628	static struct flb_config_map config_map[] = {
629	    {
630	     FLB_CONFIG_MAP_STR, "database", "fluentbit",
631	     0, FLB_TRUE, offsetof(struct flb_influxdb, database),
632	     "Set the database name."
633	    },
634	    {
635	     FLB_CONFIG_MAP_STR, "bucket", NULL,
636	     0, FLB_TRUE, offsetof(struct flb_influxdb, bucket),
637	     "Specify the bucket name, used on InfluxDB API v2."
638	    },
639	
640	    {
641	     FLB_CONFIG_MAP_STR, "org", "fluent",
642	     0, FLB_TRUE, offsetof(struct flb_influxdb, organization),
643	     "Set the Organization name."
644	    },
645	
646	    {
647	     FLB_CONFIG_MAP_STR, "sequence_tag", NULL,
648	     0, FLB_FALSE, 0,
649	     "Specify the sequence tag."
650	    },
651	
652	    {
653	     FLB_CONFIG_MAP_STR, "uri", NULL,
654	     0, FLB_TRUE, offsetof(struct flb_influxdb, custom_uri),
655	     "Specify a custom URI endpoint (must start with '/')."
656	    },
657	
658	    {
