660	     0, FLB_TRUE, offsetof(struct flb_influxdb, http_user),
661	     "HTTP Basic Auth username."
662	    },
663	
664	    {
665	     FLB_CONFIG_MAP_STR, "http_passwd", "",
666	     0, FLB_TRUE, offsetof(struct flb_influxdb, http_passwd),
667	     "HTTP Basic Auth password."
668	    },
669	
670	    {
671	     FLB_CONFIG_MAP_STR, "http_token", NULL,
672	     0, FLB_TRUE, offsetof(struct flb_influxdb, http_token),
673	     "Set InfluxDB HTTP Token API v2."
674	    },
