676	    {
677	     FLB_CONFIG_MAP_SLIST_1, "http_header", NULL,
678	     FLB_CONFIG_MAP_MULT, FLB_TRUE, offsetof(struct flb_influxdb, headers),
679	     "Add a HTTP header key/value pair. Multiple headers can be set"
680	    },
681	
682	    {
683	     FLB_CONFIG_MAP_BOOL, "auto_tags", "false",
684	     0, FLB_TRUE, offsetof(struct flb_influxdb, auto_tags),
