173	void flb_test_basic()
174	{
175	    int ret;
176	    int size = sizeof(JSON_BASIC) - 1;
177	    flb_ctx_t *ctx;
178	    int in_ffd;
179	    int out_ffd;
180	
181	    clear_output_num();
182	
183	    /* Create context, flush every second (some checks omitted here) */
184	    ctx = flb_create();
185	    flb_service_set(ctx, "flush", "1", "grace", "1",
186	                    "log_level", "error",
187	                    NULL);
188	
189	    /* Lib input mode */
190	    in_ffd = flb_input(ctx, (char *) "lib", NULL);
191	    flb_input_set(ctx, in_ffd, "tag", "test", NULL);
192	
193	    /* Elasticsearch output */
194	    out_ffd = flb_output(ctx, (char *) "influxdb", NULL);
195	    flb_output_set(ctx, out_ffd,
196	                   "match", "test",
197	                   NULL);
198	
199	    /* Enable test mode */
200	    ret = flb_output_set_test(ctx, out_ffd, "formatter",
201	                              cb_check_basic,
202	                              NULL, NULL);
203	
204	    /* Start */
205	    ret = flb_start(ctx);
206	    TEST_CHECK(ret == 0);
207	
208	    /* Ingest data sample */
209	    ret = flb_lib_push(ctx, in_ffd, (char *) JSON_BASIC, size);
210	    TEST_CHECK(ret >= 0);
211	
212	    sleep(2);
213	
214	    ret = get_output_num();
215	    if (!TEST_CHECK(ret != 0)) {
216	        TEST_MSG("no output");
217	    }
218	
219	    flb_stop(ctx);
220	    flb_destroy(ctx);
221	}
