#define JSON_TAG_KEYS "[12345678, {\"ldap_server\":\"server1\",\"client_ip\":\"10.0.0.1\",\"dn\":\"cn=admin\",\"value\":\"some_val\"}]"
static void cb_check_tag_keys(void *ctx, int ffd,
                               int res_ret, void *res_data, size_t res_size,
                               void *data)
{
    char *p;
    flb_sds_t out = res_data;

    set_output_num(1);

    printf("DEBUG_OUTPUT_START[%.*s]DEBUG_OUTPUT_END\n", (int)res_size, (char *)res_data);

    /* tag_keys should be comma-separated in the influxdb line protocol as tags */
    p = strstr(out, "ldap_server=server1");
    if (!TEST_CHECK(p != NULL)) {
      TEST_MSG("tag_keys should contain ldap_server=server1. Got:%.*s", (int)res_size, out);
    }
    p = strstr(out, "client_ip=10.0.0.1");
    if (!TEST_CHECK(p != NULL)) {
      TEST_MSG("tag_keys should contain client_ip=10.0.0.1. Got:%.*s", (int)res_size, out);
    }
    p = strstr(out, "dn=cn=admin");
    if (!TEST_CHECK(p != NULL)) {
      TEST_MSG("tag_keys should contain dn=cn=admin. Got:%.*s", (int)res_size, out);
    }

    flb_free(out);
}

void flb_test_tag_keys()
{
    int ret;
